  orientation: "horizontal" | "vertical"
}

const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

type StepperItemContextValue = {
  step: number
}

const StepperItemContext = React.createContext<StepperItemContextValue | null>(null)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }
  return context
}

// ─── Variants ─────────────────────────────────────────────────────────────────

const stepperTriggerVariants = cva(
  "relative z-10 flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50",
  {
    variants: {
      state: {
        pending: "border-border bg-background text-muted-foreground",
        active: "border-primary bg-primary text-primary-foreground",
        completed: "border-primary bg-primary text-primary-foreground",
      },
    },
    defaultVariants: {
      state: "pending",
    },
  }
)

// ─── Types ────────────────────────────────────────────────────────────────────

type StepState = "completed" | "active" | "pending"

function getStepState(step: number, activeStep: number): StepState {
  if (step < activeStep) return "completed"
  if (step === activeStep) return "active"
  return "pending"
}

// ─── Components ───────────────────────────────────────────────────────────────

function Stepper({
  orientation = "horizontal",
  activeStep,
  className,
  ...props
}: React.ComponentProps<"div"> & {
  orientation?: "horizontal" | "vertical"
  activeStep: number
}) {
  return (
    <StepperContext.Provider value={{ activeStep, orientation }}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "flex",
          orientation === "horizontal" ? "flex-row items-start" : "flex-col",
          className
        )}
        {...props}
      />
    </StepperContext.Provider>
  )
}

function StepperItem({
  step,
  className,
  ...props
}: React.ComponentProps<"div"> & { step: number }) {
  const { activeStep, orientation } = useStepper()
  const state = getStepState(step, activeStep)

  return (
    <StepperItemContext.Provider value={{ step }}>
      <div
        data-slot="stepper-item"
        data-step={step}
        data-state={state}
        className={cn(
          "relative flex flex-1",
          orientation === "horizontal"
            ? "flex-col items-center gap-1.5"
            : "flex-row items-start gap-4",
          className
        )}
        {...props}
      />
    </StepperItemContext.Provider>
  )
}

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { activeStep } = useStepper()
  const { step } = useStepperItem()
  const state = getStepState(step, activeStep)

  return (
    <button
      data-slot="stepper-trigger"
      data-state={state}
      type="button"
      className={cn(stepperTriggerVariants({ state }), className)}
      {...props}
    >
      {children ?? step}
    </button>
  )
}

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-title"
      className={cn("text-sm font-medium", className)}
      {...props}
    />
  )
}

function StepperDescription({ className, ...props }: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-xs text-muted-foreground", className)}
      {...props}
    />
  )
}

function StepperSeparator({ className, ...props }: React.ComponentProps<"div">) {
  const { activeStep, orientation } = useStepper()
  const { step } = useStepperItem()
  const isActive = activeStep > step

  return (
    <div
      data-slot="stepper-separator"
      data-orientation={orientation}
      data-active={isActive}
      className={cn(
        "absolute bg-border transition-colors",
        isActive && "bg-primary",
        orientation === "horizontal"
          ? "top-4 left-1/2 h-px w-full"
          : "left-4 top-8 h-full w-px",
        className
      )}
      {...props}
    />
  )
}

function StepperContent({
  step,
  className,
  ...props
}: React.ComponentProps<"div"> & { step: number }) {
  const { activeStep } = useStepper()

  if (step !== activeStep) {
    return null
  }

  return (
    <div
      data-slot="stepper-content"
      className={cn("w-full", className)}
      {...props}
    />
  )
}

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
}

