"use client"

import * as React from "react"

import {
  Stepper,
  StepperContent,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

const steps = [
  {
    step: 1,
    title: "Account",
    content: {
      heading: "Create your account",
      body: "Enter your email address and choose a secure password to get started.",
    },
  },
  {
    step: 2,
    title: "Profile",
    content: {
      heading: "Set up your profile",
      body: "Add your name, avatar, and a short bio so others can find you.",
    },
  },
  {
    step: 3,
    title: "Complete",
    content: {
      heading: "You're all set!",
      body: "Your account is ready. Start exploring the platform.",
    },
  },
]

export default function StepperDemo() {
  const [activeStep, setActiveStep] = React.useState(1)

  return (
    <div className="w-full max-w-md px-4">
      {/* className overrides the default flex-row so the indicator row,
          content panels, and nav buttons stack vertically. The orientation
          prop value ("horizontal") is still passed through context so that
          StepperItem and StepperSeparator use horizontal layout internally. */}
      <Stepper
        activeStep={activeStep}
        orientation="horizontal"
        className="flex-col items-stretch gap-8"
      >
        {/* Step indicator row */}
        <div className="flex flex-row items-start">
          {steps.map(({ step, title }, index) => (
            <StepperItem key={step} step={step}>
              <StepperTrigger onClick={() => setActiveStep(step)} />
              <StepperTitle>{title}</StepperTitle>
              {index < steps.length - 1 && <StepperSeparator />}
            </StepperItem>
          ))}
        </div>

        {/* Content panels — only the active step renders */}
        {steps.map(({ step, content }) => (
          <StepperContent key={step} step={step}>
            <div className="rounded-lg border p-4">
              <h3 className="font-medium">{content.heading}</h3>
              <p className="mt-1 text-sm text-muted-foreground">{content.body}</p>
            </div>
          </StepperContent>
        ))}

        {/* Navigation */}
        <div className="flex gap-2">
          <button
            onClick={() => setActiveStep((s) => Math.max(1, s - 1))}
            disabled={activeStep === 1}
            className="inline-flex h-9 items-center justify-center rounded-md border border-input bg-background px-4 text-sm font-medium shadow-sm transition-colors hover:bg-accent hover:text-accent-foreground disabled:pointer-events-none disabled:opacity-50"
          >
            Previous
          </button>
          <button
            onClick={() => setActiveStep((s) => Math.min(steps.length, s + 1))}
            disabled={activeStep === steps.length}
            className="inline-flex h-9 items-center justify-center rounded-md bg-primary px-4 text-sm font-medium text-primary-foreground shadow transition-colors hover:bg-primary/90 disabled:pointer-events-none disabled:opacity-50"
          >
            Next
          </button>
        </div>
      </Stepper>
    </div>
  )
}

